import { Link } from "react-router-dom";

export default function ForgotPassword() {
  return (
    <div className="page">
      <div className="page-header">
        <h1>Forgot Password</h1>
        <p>Contact support to reset your password securely.</p>
      </div>
      <div className="card">
        <p>Use your registered account details for password recovery.</p>
        <Link to="/login">Back to Sign In</Link>
      </div>
    </div>
  );
}
